from flask import Flask, redirect, request
from flask_oauthlib.client import OAuth

app = Flask(__name__)

oauth = OAuth()

client = oauth.register(
    'oauth2',
    client_id='YOUR_CLIENT_ID',
    client_secret='YOUR_CLIENT_SECRET',
    authorize_url='YOUR_AUTHORIZE_URL',
    access_token_url='YOUR_ACCESS_TOKEN_URL',
)

@app.route('/authorize')
def authorize():
    redirect_uri = request.args.get('redirect_uri')
    if not redirect_uri or 'YOUR_DOMAIN' not in redirect_uri:
        return 'Invalid redirect URI.', 400

    return redirect(client.authorize(redirect_uri=redirect_uri))

if __name__ == '__main__':
    app.run(debug=True)